from anthropic import Anthropic

client = Anthropic()

response = client.messages.create(
    model="claude-sonnet-4-20250514",
    max_tokens=512,
    stop_sequences=["</answer>"],
    messages=[{
        "role": "user",
        "content": (
            "Analyze the following function and output your conclusion inside "
            "<answer>...</answer> tags.\n"
            "def add(a, b): return a - b"
        )
    }]
)

text = response.content[0].text
reason = response.stop_reason  # Anthropic uses stop_reason

if reason == "max_tokens":
    print("WARNING: output truncated. Raise max_tokens.")
elif reason == "stop_sequence":
    print("Clean stop. Extracted:", text)
elif reason == "end_turn":
    print("Natural stop:", text)

