// OpenAI Node.js — streaming with finish_reason check
import OpenAI from 'openai';

const client = new OpenAI();

const stream = await client.chat.completions.stream({
  model: 'gpt-4o-mini',
  messages: [{ role: 'user', content: 'Summarize quantum computing in 3 sentences.' }],
  max_tokens: 200,
  stop: ['</summary>'],
});

let fullText = '';
for await (const chunk of stream) {
  const delta = chunk.choices[0]?.delta?.content ?? '';
  fullText += delta;
  process.stdout.write(delta);
}

const finalMessage = await stream.finalMessage();
const finishReason = finalMessage.choices[0].finish_reason;

if (finishReason === 'length') {
  console.error('\nWARNING: Output was truncated — raise max_tokens.');
}
